# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify, Response
import jwt
import requests
import json

app = Flask(__name__)

BACKEND_SERVICES = {
    'users': 'http://localhost:5001',
    'orders': 'http://localhost:5002',
    'products': 'http://localhost:5003'
}

def extract_token():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        return None
    
    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != 'bearer':
        return None
    
    return parts[1]

def decode_token(token):
    try:
        decoded = jwt.decode(token, options={'verify_signature': False})
        return decoded
    except Exception as e:
        return None

def forward_to_backend(service_name, path):
    if service_name not in BACKEND_SERVICES:
        return jsonify({'error': 'Service not found'}), 404
    
    token = extract_token()
    if not token:
        return jsonify({'error': 'No token provided'}), 401
    
    claims = decode_token(token)
    if not claims:
        return jsonify({'error': 'Invalid token'}), 401
    
    backend_url = f"{BACKEND_SERVICES[service_name]}{path}"
    
    headers = {
        'Authorization': request.headers.get('Authorization'),
        'X-User-Id': str(claims.get('user_id', '')),
        'X-User-Email': str(claims.get('email', '')),
        'X-User-Role': str(claims.get('role', '')),
        'X-User-Claims': json.dumps(claims),
        'Content-Type': request.headers.get('Content-Type', 'application/json')
    }
    
    try:
        if request.method == 'GET':
            response = requests.get(backend_url, headers=headers, params=request.args)
        elif request.method == 'POST':
            response = requests.post(backend_url, headers=headers, json=request.get_json(), params=request.args)
        elif request.method == 'PUT':
            response = requests.put(backend_url, headers=headers, json=request.get_json(), params=request.args)
        elif request.method == 'DELETE':
            response = requests.delete(backend_url, headers=headers, params=request.args)
        elif request.method == 'PATCH':
            response = requests.patch(backend_url, headers=headers, json=request.get_json(), params=request.args)
        else:
            return jsonify({'error': 'Method not allowed'}), 405
        
        return Response(
            response.content,
            status=response.status_code,
            headers=dict(response.headers)
        )
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Backend service unavailable'}), 503

@app.route('/users', methods=['GET', 'POST'])
@app.route('/users/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def users_gateway(path=''):
    return forward_to_backend('users', f'/{path}' if path else '/')

@app.route('/orders', methods=['GET', 'POST'])
@app.route('/orders/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def orders_gateway(path=''):
    return forward_to_backend('orders', f'/{path}' if path else '/')

@app.route('/products', methods=['GET', 'POST'])
@app.route('/products/<path:path>', methods=['GET', 'POST', 'PUT', 'DELETE', 'PATCH'])
def products_gateway(path=''):
    return forward_to_backend('products', f'/{path}' if path else '/')

@app.route('/health', methods=['GET'])
def health():
    return jsonify({'status': 'healthy'}), 200

@app.route('/verify', methods=['GET'])
def verify():
    token = extract_token()
    if not token:
        return jsonify({'error': 'No token provided'}), 401
    
    claims = decode_token(token)
    if not claims:
        return jsonify({'error': 'Invalid token'}), 401
    
    return jsonify({'valid': True, 'claims': claims}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)